{
    int t; // Variable to store the number of test cases
    cin >> t; // Read the number of test cases

    // Loop over each test case
    for (int i = 1; i <= t; i++)
    {
        int n; // Variable to store the number of elements in the current test case
        long long gift_num = 0, temp = 0; // Initialize gift count and temporary variable

        cin >> n; // Read the number of elements
        // Read the elements into the input array
        for (int i = 0; i < n; i++)
        {
            cin >> arr[i]; // Read each element
        }

        brr[0] = 1; // Initialize the first element of the brr array

        // Populate brr array based on the increasing sequence of arr
        for (int i = 1; i < n; i++)
        {
            // Check if the current element is greater than the previous one
            if (arr[i] > arr[i - 1])
            {
                // Increment the count of gifts
                brr[i] = brr[i - 1] + 1;
            }
            else
            {
                // Reset the count of gifts to 1 if the sequence is not increasing
                brr[i] = 1;
            }
        }

        // Set the initial gift number based on the last element of brr
        gift_num = brr[n - 1];

        // Traverse the brr array in reverse to count gifts for decreasing sequences
        for (int i = n - 2; i >= 0; i--)
        {
            // Check if the current element is greater than the next one
            if (arr[i] > arr[i + 1])
            {
                // If true, increment temp based on the next brr value
                temp = brr[i + 1] + 1;
            }
            else
            {
                // Reset temp to 1 if the sequence is not decreasing
                temp = 1;
            }
