    {
        Scanner sc = new Scanner(System.in); // Create a Scanner object for input
        int t = sc.nextInt(); // Read the number of test cases

        // Loop over each test case
        for (int i = 1; i <= t; i++)
        {
            int n = sc.nextInt(); // Read the number of elements in the current test case
            long[] arr = new long[n]; // Array to store the input values
            long[] brr = new long[n]; // Array to store the number of gifts
            long gift_num = 0, temp = 0; // Initialize gift count and temporary variable

            // Read the elements into the input array
            for (int j = 0; j < n; j++)
            {
                arr[j] = sc.nextLong(); // Read each long integer element
            }

            brr[0] = 1; // Initialize the first element of the brr array to 1

            // Populate the brr array based on the increasing sequence of arr
            for (int j = 1; j < n; j++)
            {
                // Check if the current element is greater than the previous one
                if (arr[j] > arr[j - 1])
                {
                    brr[j] = brr[j - 1] + 1; // Increment gift count for increasing sequence
                }
                else
                {
                    brr[j] = 1; // Reset gift count to 1 if the sequence is not increasing
                }
            }

            // Set the initial gift number based on the last element of brr
            gift_num = brr[n - 1];

            // Traverse the brr array in reverse to count gifts for decreasing sequences
            for (int j = n - 2; j >= 0; j--)
            {
                // Check if the current element is greater than the next one
                if (arr[j] > arr[j + 1])
                {
                    temp = brr[j + 1] + 1; // Increment temp based on the next brr value
                }
                else
                {
                    temp = 1; // Reset temp to 1 if the sequence is not decreasing
                }
                // Update the total number of gifts by adding the maximum of temp and current brr value
                gift_num += Math.max(temp, brr[j]);
                // Update brr[j] with the new temp value for the next iteration
                brr[j] = temp;
            }

            // Output the total number of gifts for the current test case
            System.out.println(gift_num);
        }

        sc.close(); // Close the Scanner object to free resources
    }
}

