function main() {
    const readline = require('readline');
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    const input = [];
    rl.on('line', (line) => {
        input.push(line);
    }).on('close', () => {
        const T = parseInt(input[0]); // Read the number of test cases
        let index = 1;
        const results = [];

        // Loop over each test case
        for (let t = 0; t < T; t++) {
            const N = parseInt(input[index]); // Read the number of elements in the current test case
            const arr = input[index + 1].split(' ').map(Number); // Read and convert the elements into an array
            index += 2; // Move to the next test case

            const brr = new Array(N).fill(0); // Array to store the number of gifts
            let gift_num = 0; // Initialize gift count
            let temp = 0; // Temporary variable for counting

            brr[0] = 1; // Initialize the first element of the brr array to 1

            // Populate the brr array based on the increasing sequence of arr
            for (let j = 1; j < N; j++) {
                // Check if the current element is greater than the previous one
                if (arr[j] > arr[j - 1]) {
                    brr[j] = brr[j - 1] + 1; // Increment gift count for increasing sequence
                } else {
                    brr[j] = 1; // Reset gift count to 1 if the sequence is not increasing
                }
            }

            // Set the initial gift number based on the last element of brr
            gift_num = brr[N - 1];

            // Traverse the brr array in reverse to count gifts for decreasing sequences
            for (let j = N - 2; j >= 0; j--) {
                // Check if the current element is greater than the next one
                if (arr[j] > arr[j + 1]) {
                    temp = brr[j + 1] + 1; // Increment temp based on the next brr value
                } else {
                    temp = 1; // Reset temp to 1 if the sequence is not decreasing
                }
                // Update the total number of gifts by adding the maximum of temp and current brr value
                gift_num += Math.max(temp, brr[j]);
                // Update brr[j] with the new temp value for the next iteration
                brr[j] = temp;
            }

            // Store the result for the current test case
            results.push(gift_num);
        }

        // Output all results, one per line
        console.log(results.join('\n'));
    });
}

